    57→    const firstPage = await projectsApi.list(1, 100);
    58→    return firstPage;
    59→  });
    60→
    61→  /* Fetch releases — scoped by project or all */
    62→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    63→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    64→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE)
    65→  );
    66→
    67→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    68→    projectFilter === "all" ? ["all-releases", page] : null,
    69→    () => releasesApi.list(page, PER_PAGE)
